+function sanitizeLines(lines: string[]): string[] {
+  return lines.map((l) =>
+    l
+      // Drop ANSI escapes
+      .replace(/[\\u001b]\[[0-?]*[ -/]*[@-~]/g, '')
+      // Drop leading icons/bullets
+      .replace(/^[^\w]+/u, '')
+      .trim()
+  );
+}
